// Generate research prompt based on current state
const phase = $input.first().json.phase;
const round = $input.first().json.round;
const userInput = $input.first().json.userInput;
const refinementHistory = $input.first().json.refinementHistory || [];

let prompt = `Research Phase - Round ${round}\n\n`;
prompt += `User Request: ${userInput}\n\n`;

if (round > 1 && refinementHistory.length > 0) {
  prompt += `Previous feedback:\n${refinementHistory.join('\n')}\n\n`;
  prompt += `Please address the following points:\n`;
  refinementHistory.forEach((item, index) => {
    prompt += `${index + 1}. ${item}\n`;
  });
  prompt += `\n`;
}

prompt += `Instructions:\n`;
prompt += `1. Conduct comprehensive research on the topic\n`;
prompt += `2. Use reliable sources and cite them\n`;
prompt += `3. Provide structured findings\n`;
prompt += `4. Focus on accuracy and relevance\n`;
prompt += `5. Return response in JSON format with sections: summary, findings, sources, recommendations`;

return {
  prompt,
  phase,
  round,
  userInput
};

// Generate analysis prompt based on research document
const phase = $input.first().json.phase;
const round = $input.first().json.round;
const researchDoc = $input.first().json.documents?.research || {};
const refinementHistory = $input.first().json.refinementHistory || [];

let prompt = `Analysis Phase - Round ${round}\n\n`;
prompt += `Research Document:\n${JSON.stringify(researchDoc, null, 2)}\n\n`;

if (round > 1 && refinementHistory.length > 0) {
  prompt += `Previous feedback:\n${refinementHistory.join('\n')}\n\n`;
  prompt += `Please address the following points:\n`;
  refinementHistory.forEach((item, index) => {
    prompt += `${index + 1}. ${item}\n`;
  });
  prompt += `\n`;
}

prompt += `Instructions:\n`;
prompt += `1. Analyze the research findings critically\n`;
prompt += `2. Identify vulnerabilities and opportunities\n`;
prompt += `3. Assess risks and potential impacts\n`;
prompt += `4. Provide structured analysis\n`;
prompt += `5. Return response in JSON format with sections: analysis, vulnerabilities, opportunities, risks, recommendations`;

return {
  prompt,
  phase,
  round,
  researchDoc
};

// Generate planning prompt based on research and analysis
const phase = $input.first().json.phase;
const round = $input.first().json.round;
const researchDoc = $input.first().json.documents?.research || {};
const analysisDoc = $input.first().json.documents?.analysis || {};
const refinementHistory = $input.first().json.refinementHistory || [];

let prompt = `Plan Phase - Round ${round}\n\n`;
prompt += `Research Document:\n${JSON.stringify(researchDoc, null, 2)}\n\n`;
prompt += `Analysis Document:\n${JSON.stringify(analysisDoc, null, 2)}\n\n`;

if (round > 1 && refinementHistory.length > 0) {
  prompt += `Previous feedback:\n${refinementHistory.join('\n')}\n\n`;
  prompt += `Please address the following points:\n`;
  refinementHistory.forEach((item, index) => {
    prompt += `${index + 1}. ${item}\n`;
  });
  prompt += `\n`;
}

prompt += `Instructions:\n`;
prompt += `1. Create actionable implementation plan\n`;
prompt += `2. Use insights from research and analysis\n`;
prompt += `3. Define clear steps and timelines\n`;
prompt += `4. Identify resources and dependencies\n`;
prompt += `5. Return response in JSON format with sections: plan, steps, timeline, resources, success_metrics`;

return {
  prompt,
  phase,
  round,
  researchDoc,
  analysisDoc
};

// Merge all agent responses
const responses = [];
const errors = [];

// Collect successful responses
$input.all().forEach((item, index) => {
  if (item.json && item.json.choices && item.json.choices[0]) {
    responses.push({
      agent: item.json.agent || `Agent_${index}`,
      content: item.json.choices[0].message.content,
      timestamp: new Date().toISOString()
    });
  } else if (item.error) {
    errors.push({
      agent: item.json.agent || `Agent_${index}`,
      error: item.error.message || 'Unknown error'
    });
  }
});

// Prepare committee package
const committeePackage = {
  phase: $input.first().json.phase,
  round: $input.first().json.round,
  responses,
  errors,
  totalAgents: 6,
  successfulResponses: responses.length,
  timestamp: new Date().toISOString()
};

return {
  committeePackage,
  responses,
  errors,
  phase: $input.first().json.phase,
  round: $input.first().json.round
};

// Committee evaluation using DeepSeek R1T2 Chimera
const committeePackage = $input.first().json.committeePackage;
const responses = $input.first().json.responses;

// Create evaluation prompt
let evaluationPrompt = `Committee Evaluation - ${committeePackage.phase.toUpperCase()} Phase\n\n`;
evaluationPrompt += `Round: ${committeePackage.round}\n`;
evaluationPrompt += `Total Responses: ${committeePackage.totalAgents}\n`;
evaluationPrompt += `Successful Responses: ${committeePackage.successfulResponses}\n\n`;

evaluationPrompt += `Agent Responses:\n`;
responses.forEach((response, index) => {
  evaluationPrompt += `\nAgent ${index + 1} (${response.agent}):\n${response.content}\n`;
});

evaluationPrompt += `\n\nEvaluation Instructions:\n`;
evaluationPrompt += `1. Analyze the quality and consistency of responses\n`;
evaluationPrompt += `2. Calculate consensus score (0-100%)\n`;
evaluationPrompt += `3. Identify key divergence points\n`;
evaluationPrompt += `4. Provide specific recommendations for improvement\n`;
evaluationPrompt += `5. Return JSON with: consensus_score, divergence_points, recommendations, quality_assessment`;

return {
  evaluationPrompt,
  committeePackage,
  phase: committeePackage.phase,
  round: committeePackage.round
};

// Parse committee evaluation and check consensus
const evaluation = $input.first().json;
let consensusScore = 0;
let divergencePoints = [];
let recommendations = [];

// Try to parse the evaluation response
if (evaluation.choices && evaluation.choices[0]) {
  try {
    const content = evaluation.choices[0].message.content;
    const parsed = JSON.parse(content);
    consensusScore = parsed.consensus_score || 0;
    divergencePoints = parsed.divergence_points || [];
    recommendations = parsed.recommendations || [];
  } catch (e) {
    // Fallback parsing
    const content = evaluation.choices[0].message.content;
    const scoreMatch = content.match(/consensus_score[\s:]*([0-9]+)/i);
    if (scoreMatch) consensusScore = parseInt(scoreMatch[1]);
  }
}

const hasConsensus = consensusScore >= 85;
const canRetry = $input.first().json.round < $input.first().json.maxRounds;

return {
  consensusScore,
  divergencePoints,
  recommendations,
  hasConsensus,
  canRetry,
  phase: $input.first().json.phase,
  round: $input.first().json.round,
  maxRounds: $input.first().json.maxRounds
};

// Synthesize final document based on consensus
const responses = $input.first().json.responses;
const consensusScore = $input.first().json.consensusScore;
const phase = $input.first().json.phase;

// Create synthesis prompt
let synthesisPrompt = `Synthesize ${phase.toUpperCase()} Document\n\n`;
synthesisPrompt += `Consensus Score: ${consensusScore}%\n`;
synthesisPrompt += `Number of Responses: ${responses.length}\n\n`;

synthesisPrompt += `Agent Responses:\n`;
responses.forEach((response, index) => {
  synthesisPrompt += `\nAgent ${index + 1}:\n${response.content}\n`;
});

synthesisPrompt += `\n\nInstructions:\n`;
synthesisPrompt += `1. Create a comprehensive, well-structured document\n`;
synthesisPrompt += `2. Resolve any contradictions between responses\n`;
synthesisPrompt += `3. Highlight areas of strong consensus\n`;
synthesisPrompt += `4. Provide clear, actionable insights\n`;
synthesisPrompt += `5. Return a professional, publication-ready document`;

return {
  synthesisPrompt,
  phase,
  consensusScore,
  responses
};

// Store responses and increment round for retry
const currentState = $input.first().json;
const responses = currentState.responses;
const round = currentState.round;
const phase = currentState.phase;

// Store current responses in refinement history
const refinementHistory = currentState.refinementHistory || [];
refinementHistory.push({
  round,
  phase,
  responses,
  timestamp: new Date().toISOString()
});

// Increment round
const newRound = round + 1;

// Update state for retry
const updatedState = {
  ...currentState,
  round: newRound,
  refinementHistory,
  lastRefinement: {
    round,
    phase,
    timestamp: new Date().toISOString()
  }
};

return updatedState;

// Finalize best available document when max rounds reached
const currentState = $input.first().json;
const responses = currentState.responses;
const phase = currentState.phase;
const round = currentState.round;

// Create finalization prompt
let finalizationPrompt = `Finalize ${phase.toUpperCase()} Document (Max Rounds Reached)\n\n`;
finalizationPrompt += `Round: ${round}\n`;
finalizationPrompt += `Number of Responses: ${responses.length}\n\n`;

finalizationPrompt += `Available Responses:\n`;
responses.forEach((response, index) => {
  finalizationPrompt += `\nAgent ${index + 1}:\n${response.content}\n`;
});

finalizationPrompt += `\n\nInstructions:\n`;
finalizationPrompt += `1. Create the best possible document from available responses\n`;
finalizationPrompt += `2. Acknowledge limitations due to max rounds\n`;
finalizationPrompt += `3. Highlight areas of agreement\n`;
finalizationPrompt += `4. Note areas requiring further investigation\n`;
finalizationPrompt += `5. Return a professional document with caveats`;

return {
  finalizationPrompt,
  phase,
  round,
  responses,
  maxRoundsReached: true
};

// Phase transition logic
const currentPhase = $input.first().json.phase;
const nextPhase = {
  'research': 'analysis',
  'analysis': 'plan',
  'plan': 'complete'
}[currentPhase];

if (nextPhase === 'complete') {
  return {
    action: 'complete',
    message: 'All phases completed successfully',
    finalDocuments: $input.first().json.documents
  };
} else {
  // Update state for next phase
  const updatedState = {
    ...$input.first().json,
    phase: nextPhase,
    round: 1,
    refinementHistory: []
  };

  return {
    action: 'transition',
    nextPhase,
    updatedState
  };
}

// Generate final comprehensive report
const researchDoc = $input.first().json.documents?.research || {};
const analysisDoc = $input.first().json.documents?.analysis || {};
const planDoc = $input.first().json.documents?.plan || {};

const finalReport = {
  executive_summary: {
    research_highlights: researchDoc.summary || 'Research summary not available',
    key_insights: analysisDoc.insights || 'Analysis insights not available',
    action_items: planDoc.action_items || 'Action items not available'
  },
  detailed_findings: {
    research: researchDoc,
    analysis: analysisDoc,
    plan: planDoc
  },
  recommendations: {
    immediate: planDoc.immediate_actions || [],
    short_term: planDoc.short_term_goals || [],
    long_term: planDoc.long_term_strategy || []
  },
  metadata: {
    generated_at: new Date().toISOString(),
    total_phases: 3,
    consensus_scores: $input.first().json.consensusScores || [],
    refinement_rounds: $input.first().json.refinementHistory?.length || 0
  }
};

return {
  finalReport,
  timestamp: new Date().toISOString()
};

// Error handling and fallback
const error = $input.first().error || 'Unknown error occurred';
const phase = $input.first().json?.phase || 'unknown';
const round = $input.first().json?.round || 1;

// Log error
console.error(`Error in ${phase} phase, round ${round}:`, error);

// Determine fallback action
let fallbackAction = 'retry';
let fallbackMessage = `Error in ${phase} phase, round ${round}. Attempting retry.`;

if (round >= 4) {
  fallbackAction = 'finalize';
  fallbackMessage = `Max rounds reached in ${phase} phase. Finalizing with available data.`;
}

return {
  error,
  phase,
  round,
  fallbackAction,
  fallbackMessage,
  timestamp: new Date().toISOString()
};
